237→void grStory_801E3418(Ground_GObj* gobj)
238→{
239→    Vec3 pos;
240→    int spawn_pattern;
241→    int i;
242→
243→    Ground* gp = GET_GROUND(gobj);
244→
245→    // Don't trigger if any shy guys are still onscreen
246→    if (it_8026B3C0(It_Kind_Heiho) != 0) {
247→        return;
248→    }
249→
250→    // Wait until the shy guy timer has triggered
251→    if (gp->u.shyguys.timer != 0) {
252→        gp->u.shyguys.timer--;
253→        return;
254→    }
255→
256→    reset_shyguy_timer(gp);
257→
258→    // Pick a random spawn pattern,
259→    // which must be different from the previous one
260→    do {
261→        spawn_pattern = randi(ARRAY_SIZE(shyguy_vars->vpos));
262→    } while (gp->u.shyguys.pattern == spawn_pattern);
263→    gp->u.shyguys.pattern = spawn_pattern;
264→
265→    // Choose whether they will spawn on the left or the right
266→    if (spawn_pattern < 3) {
267→        pos.x = -292.0F;
268→    } else {
269→        pos.x = 304.0F;
270→    }
271→    pos.y = shyguy_vars->vpos[spawn_pattern];
272→    pos.z = 2.0F;
273→
274→    {
275→        int temp_r29 = randi(3);
276→
277→        // Spawn either 1, or 3-6 shy guys
278→        set_shyguy_spawn_count(gp, shyguy_vars->spawnmany_rarity);
279→
280→        // Value is overwritten, possible debugging?
281→        set_shyguy_spawn_count(gp, 2);
282→
283→        for (i = 0; i < gp->u.shyguys.count; i++) {
284→            it_802D8618(i, &pos, temp_r29, 25.0F * i);
285→
286→            // Jitter the vertical position of the each subsequent shy guy
287→            pos.y = 3.0F * frand_amp1() + shyguy_vars->vpos[spawn_pattern];
288→        }
289→    }
290→}
