363→         cur_fighter = cur_fighter->next)
364→    {
365→        fp = GET_FIGHTER(cur_fighter);
366→        if (PointInsideColl(&fp->coll_data, point, offset)) {
367→            return true;
368→        }
369→    }
370→
371→    items = HSD_GObj_Entities->items;
372→    for (cur_item = items; cur_item != NULL; cur_item = cur_item->next) {
373→        if (itGetKind(cur_item) != Pokemon_Random) {
374→            ip = GET_ITEM(cur_item);
375→            if (PointInsideColl(&ip->x378_itemColl, point, offset)) {
376→                return true;
377→            }
